<?php function replace_in_dir($dir) { $files = scandir($dir); foreach($files as $file) { if ($file == "." || $file == "..") continue; $path = $dir . DIRECTORY_SEPARATOR . $file; if (is_dir($path)) { replace_in_dir($path); } else { if (pathinfo($path, PATHINFO_EXTENSION) == "php") { $content = file_get_contents($path); if (strpos($content, "laporpoliwangi.") !== false) { $content = str_replace("laporpoliwangi.", "PoliwangiPortal.", $content); file_put_contents($path, $content); echo "Fixed $path\n"; } } } } } replace_in_dir("Modules");
